function canUseFreeRiffMeter(numerator: number): boolean {
  return FREE_RIFF_METERS.includes(Math.round(numerator) as (typeof FREE_RIFF_METERS)[number]);
}

function canUseFreeRiffSubdivision(subdivision: number): boolean {
  return FREE_RIFF_SUBDIVISIONS.includes(Math.round(subdivision) as (typeof FREE_RIFF_SUBDIVISIONS)[number]);
}

function normalizeRiffBackbeatBeats(
  beats: number[] | undefined,
  numerator: number,
  fallbackBeat: number | null | undefined,
): number[] {
  const normalizedNumerator = Math.max(2, Math.min(32, Math.round(numerator || 0)));
  const source = beats && beats.length > 0 ? beats : fallbackBeat != null ? [fallbackBeat] : [Math.min(3, normalizedNumerator)];
  return Array.from(
    new Set(
      source.map((beat) => Math.max(1, Math.min(normalizedNumerator, Math.round(beat || 0)))),
    ),
  ).sort((a, b) => a - b);
}
const DEFAULT_ORBIT_TEMPO_ANCHOR_PULSE_COUNT = Math.max(
  1,
  DEFAULT_ORBITS.reduce((anchor, orbit) => (!anchor || orbit.radius > anchor.radius ? orbit : anchor), DEFAULT_ORBITS[0])?.pulseCount ?? 1,
);
const DEFAULT_SCENE_SPEED = orbitTempoBpmToSpeedMultiplier(
  DEFAULT_ORBIT_TEMPO_BPM,
  DEFAULT_BASE_BPM,
  DEFAULT_ORBIT_TEMPO_ANCHOR_PULSE_COUNT,
);
const PATTERN_MUTATION_COOLDOWN_MS = 140;
const INTERFERENCE_PREVIEW_WEIGHTS = [-1, 1, 1, -1] as const;
const DEFAULT_POLYRHYTHM_PRESET_ID = 'three-five';
const MOBILE_VIEWPORT_BREAKPOINT = 768;

function isMobileViewportNow(): boolean {
  if (typeof window === 'undefined') {
    return false;
  }
  const shortEdge = Math.min(window.innerWidth, window.innerHeight);
  const narrowViewport = window.innerWidth < MOBILE_VIEWPORT_BREAKPOINT;
  const coarsePointer = window.matchMedia?.('(pointer: coarse)')?.matches ?? false;
  const handsetLandscape = coarsePointer && shortEdge < MOBILE_VIEWPORT_BREAKPOINT;
  return narrowViewport || handsetLandscape;
}

function createInitialRiffCycleStudy(): RiffCycleStudy {
  const study = createDefaultRiffCycleStudy();
  const initialStudy: RiffCycleStudy = isMobileViewportNow() ? { ...study, viewMode: 'circular' } : study;
  return RIFF_CELL_SEQUENCE_FEATURE_ENABLED ? initialStudy : { ...initialStudy, riffSequenceEnabled: false };
}

