function sortSavedScenesByUpdatedAt(scenes: SavedScene[]): SavedScene[] {
  return [...scenes].sort(
    (a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime(),
  );
}

function upsertSavedScene(scenes: SavedScene[], scene: SavedScene): SavedScene[] {
  return sortSavedScenesByUpdatedAt([scene, ...scenes.filter((entry) => entry.id !== scene.id)]);
}

function sortSavedStudyScenesByUpdatedAt<T extends { updatedAt: string }>(scenes: T[]): T[] {
  return [...scenes].sort(
    (a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime(),
  );
}

function upsertSavedStudyScene<T extends { id: string; updatedAt: string }>(scenes: T[], scene: T): T[] {
  return sortSavedStudyScenesByUpdatedAt([scene, ...scenes.filter((entry) => entry.id !== scene.id)]);
}

function getStepStripGroupSize(stepCount: number): number {
  if (stepCount <= 8) {
    return 2;
  }
  if (stepCount <= 16) {
    return 4;
  }
  if (stepCount <= 24) {
    return 6;
  }
  if (stepCount <= 32) {
    return 8;
  }
  return 4;
}

function getPolyrhythmLayerOffsetSteps(layer: Pick<PolyrhythmLayer, 'beatCount' | 'rotationOffset'>): number {
  const normalizedOffset = ((layer.rotationOffset % 360) + 360) % 360;
  return Math.round((normalizedOffset / 360) * layer.beatCount) % Math.max(1, layer.beatCount);
}

function getRiffOffsetSteps(riff: Pick<RiffPhrase, 'stepCount' | 'rotationOffset'>): number {
  const normalizedOffset = ((riff.rotationOffset % 360) + 360) % 360;
  return Math.round((normalizedOffset / 360) * riff.stepCount) % Math.max(1, riff.stepCount);
}

function getFreeRiffResolutionBars(study: RiffCycleStudy): number {
  const phraseSteps = Math.max(1, Math.round(study.riff.stepCount || 1));
  const stepsPerBar = Math.max(1, getReferenceStepsPerBar(study.reference));
  return phraseSteps / gcd(phraseSteps, stepsPerBar);
}

function getFreeRiffResolutionCopy(study: RiffCycleStudy): string {
  const bars = getFreeRiffResolutionBars(study);
  const phraseSteps = Math.max(1, Math.round(study.riff.stepCount || 1));
  const totalSteps = bars * Math.max(1, getReferenceStepsPerBar(study.reference));
  return `Free resolves after ${bars.toLocaleString()} bar${bars === 1 ? '' : 's'} (${totalSteps.toLocaleString()} reference steps), when the ${phraseSteps}-step riff meets the bar line again.`;
}

function getRiffPatternBarMarkerCopy(study: RiffCycleStudy): string {
  const steps = Math.max(1, Math.round(study.riff.stepCount || 1));
  if (study.riff.resetMode === 'free') {
    return `Pattern cues on the riff cycle: every ${steps.toLocaleString()} step${steps === 1 ? '' : 's'}.`;
  }
  return `Pattern cues every ${steps.toLocaleString()} riff step${steps === 1 ? '' : 's'}, restarting at the return cycle.`;
}

function normalizeHexColorDraft(value: string): string | null {
  const hex = value.trim().replace(/^#/, '');
  return /^[0-9a-fA-F]{6}$/.test(hex) ? `#${hex.toUpperCase()}` : null;
}

function LimitedColorPickerButton({
  colors,
  value,
  onChange,
  label,
  iconSize = 13,
  className = 'h-8 w-8',
  locked = false,
  onLockedClick,
}: {
  colors: readonly string[];
  value: string;
  onChange: (color: string) => void;
  label: string;
  iconSize?: number;
  className?: string;
  locked?: boolean;
  onLockedClick?: () => void;
}) {
  const [open, setOpen] = useState(false);
  const buttonRef = useRef<HTMLButtonElement | null>(null);
  const popoverRef = useRef<HTMLDivElement | null>(null);
  const [position, setPosition] = useState<{ left: number; top: number } | null>(null);
  const [hexDraft, setHexDraft] = useState(value.toUpperCase());

  useEffect(() => {
    setHexDraft(value.toUpperCase());
  }, [value]);

  useEffect(() => {
    if (!open) {
      return;
    }

    const updatePosition = () => {
      const rect = buttonRef.current?.getBoundingClientRect();
      if (!rect) {
        return;
      }
      const popoverWidth = 184;
      setPosition({
        left: Math.min(Math.max(8, rect.right - popoverWidth), window.innerWidth - popoverWidth - 8),
        top: Math.min(rect.bottom + 8, window.innerHeight - 320),
      });
    };

    const handlePointerDown = (event: MouseEvent | TouchEvent) => {
      const target = event.target as Node;
      if (buttonRef.current?.contains(target) || popoverRef.current?.contains(target)) {
        return;
      }
      setOpen(false);
    };

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === 'Escape') {
        setOpen(false);
      }
    };

    updatePosition();
    window.addEventListener('resize', updatePosition);
    window.addEventListener('scroll', updatePosition, true);
    window.addEventListener('mousedown', handlePointerDown);
    window.addEventListener('touchstart', handlePointerDown);
    window.addEventListener('keydown', handleKeyDown);

    return () => {
      window.removeEventListener('resize', updatePosition);
      window.removeEventListener('scroll', updatePosition, true);
      window.removeEventListener('mousedown', handlePointerDown);
      window.removeEventListener('touchstart', handlePointerDown);
      window.removeEventListener('keydown', handleKeyDown);
    };
  }, [open]);

  return (
    <>
      <button
        ref={buttonRef}
        type="button"
        onClick={() => {
          if (locked) {
            onLockedClick?.();
            return;
          }
          setOpen((current) => !current);
        }}
        className={`relative flex cursor-pointer items-center justify-center overflow-hidden rounded-lg border transition active:scale-[0.97] ${className}`}
        style={{
          background: locked ? 'rgba(255,255,255,0.035)' : `${value}12`,
          borderColor: locked ? 'rgba(255,255,255,0.1)' : `${value}32`,
          color: locked ? 'rgba(255,255,255,0.46)' : value,
          boxShadow: locked ? 'none' : open ? `0 0 18px ${value}18` : `0 0 14px ${value}10`,
          filter: locked ? 'grayscale(0.6)' : undefined,
        }}
        aria-label={label}
        title={label}
      >
        <Palette size={iconSize} />
        {locked ? (
          <span className="pointer-events-none absolute right-0.5 top-0.5 flex h-3.5 w-3.5 items-center justify-center rounded-full border border-white/14 bg-black/40 text-white/68">
            <Lock size={8} strokeWidth={2.4} />
          </span>
        ) : null}
      </button>
      {open && position
        ? createPortal(
        <div
          ref={popoverRef}
          className="fixed z-[120] grid w-[11.5rem] grid-cols-4 gap-1.5 rounded-xl border p-2 shadow-[0_18px_44px_rgba(0,0,0,0.42)] backdrop-blur-xl"
          style={{
            left: position.left,
            top: position.top,
            background: 'rgba(17,17,22,0.94)',
            borderColor: 'rgba(255,255,255,0.12)',
          }}
        >
          {colors.map((color) => {
            const active = color.toLowerCase() === value.toLowerCase();

            return (
              <button
                key={color}
                type="button"
                onClick={() => {
                  onChange(color);
                  setOpen(false);
                }}
                className="h-7 rounded-lg border transition active:scale-[0.96]"
                style={{
                  backgroundColor: color,
                  borderColor: active ? 'rgba(255,255,255,0.95)' : 'rgba(255,255,255,0.16)',
                  boxShadow: active ? `0 0 16px ${color}aa` : `0 0 8px ${color}44`,
                  transform: active ? 'scale(1.04)' : 'scale(1)',
                }}
                aria-label={`${label}: ${color}`}
                title={color}
              />
            );
          })}
          <div className="col-span-4 mt-1 grid grid-cols-[1.75rem_1fr] gap-1.5">
            <input
              type="color"
              value={normalizeHexColorDraft(hexDraft) ?? value}
              onChange={(event) => {
                const nextColor = event.currentTarget.value.toUpperCase();
                setHexDraft(nextColor);
                onChange(nextColor);
              }}
              className="h-8 w-7 cursor-pointer rounded-lg border border-white/12 bg-transparent p-0.5"
              aria-label={`${label}: custom color`}
              title="Custom color"
            />
            <input
              type="text"
              value={hexDraft}
              onFocus={(event) => event.currentTarget.select()}
              onChange={(event) => {
                const nextDraft = event.currentTarget.value.toUpperCase();
                setHexDraft(nextDraft);
                const normalized = normalizeHexColorDraft(nextDraft);
                if (normalized) {
                  onChange(normalized);
                }
              }}
              onKeyDown={(event) => {
                if (event.key === 'Enter' && normalizeHexColorDraft(hexDraft)) {
                  setOpen(false);
                }
              }}
              placeholder="#FF88C2"
              className="min-w-0 rounded-lg border border-white/10 bg-white/[0.055] px-2 text-[10px] font-mono uppercase tracking-[0.08em] text-white outline-none placeholder:text-white/24"
              aria-label={`${label}: hex color`}
            />
          </div>
        </div>,
        document.body,
          )
        : null}
    </>
  );
}

