function InlineInfoLabel({
  infoId,
  label,
  className = '',
  labelClassName = '',
  labelStyle,
  popoverAlign = 'left',
  infoTitle,
  infoBody,
}: {
  infoId: FeatureInfoId;
  label: ReactNode;
  className?: string;
  labelClassName?: string;
  labelStyle?: CSSProperties;
  popoverAlign?: 'left' | 'right';
  infoTitle?: string;
  infoBody?: string;
}) {
  const [open, setOpen] = useState(false);
  const wrapperRef = useRef<HTMLDivElement | null>(null);
  const popoverRef = useRef<HTMLDivElement | null>(null);
  const [popoverStyle, setPopoverStyle] = useState<CSSProperties | null>(null);
  const copy = {
    title: infoTitle ?? FEATURE_INFO_COPY[infoId].title,
    body: infoBody ?? FEATURE_INFO_COPY[infoId].body,
  };

  useEffect(() => {
    if (!open) {
      return;
    }

    const handlePointerDown = (event: MouseEvent) => {
      const target = event.target as Node;
      if (!wrapperRef.current?.contains(target) && !popoverRef.current?.contains(target)) {
        setOpen(false);
      }
    };

    const handleKeyDown = (event: KeyboardEvent) => {
      if (event.key === 'Escape') {
        setOpen(false);
      }
    };

    document.addEventListener('mousedown', handlePointerDown);
    document.addEventListener('keydown', handleKeyDown);
    return () => {
      document.removeEventListener('mousedown', handlePointerDown);
      document.removeEventListener('keydown', handleKeyDown);
    };
  }, [open]);

  useEffect(() => {
    if (!open || typeof window === 'undefined') {
      return;
    }

    const updatePosition = () => {
      const triggerRect = wrapperRef.current?.getBoundingClientRect();
      if (!triggerRect) {
        return;
      }

      const width = Math.min(320, Math.max(220, window.innerWidth - 16));
      let left =
        popoverAlign === 'right'
          ? triggerRect.right - width
          : triggerRect.left;
      left = Math.max(8, Math.min(left, window.innerWidth - width - 8));

      let top = triggerRect.bottom + 8;
      const estimatedHeight = 220;
      if (top + estimatedHeight > window.innerHeight - 8) {
        top = Math.max(8, triggerRect.top - estimatedHeight - 8);
      }

      setPopoverStyle({
        position: 'fixed',
        top,
        left,
        width,
      });
    };

    updatePosition();
    window.addEventListener('resize', updatePosition);
    window.addEventListener('scroll', updatePosition, true);
    return () => {
      window.removeEventListener('resize', updatePosition);
      window.removeEventListener('scroll', updatePosition, true);
    };
  }, [open, popoverAlign]);

  return (
    <div ref={wrapperRef} className={`relative inline-flex min-w-0 items-center gap-1.5 overflow-visible align-middle leading-none ${className}`}>
      <span className={labelClassName} style={labelStyle}>
        {label}
      </span>
      <button
        type="button"
        onClick={(event) => {
          event.stopPropagation();
          setOpen((current) => !current);
        }}
        className="flex h-4.5 w-4.5 shrink-0 items-center justify-center rounded-full border border-[#88CCFF]/24 bg-[#88CCFF]/10 text-[#B7DDFF] transition active:scale-[0.96]"
        style={{ lineHeight: 1 }}
        aria-label={`What ${copy.title} means`}
        title={`What ${copy.title} means`}
      >
        <CircleHelp size={10} />
      </button>
      {open && popoverStyle && typeof document !== 'undefined'
        ? createPortal(
            <div
              ref={popoverRef}
              className="z-[90] max-h-[18rem] overflow-y-auto rounded-2xl border border-[#88CCFF]/18 bg-[#0f121a]/96 p-3 shadow-[0_22px_60px_rgba(0,0,0,0.4)] backdrop-blur-xl"
              style={popoverStyle}
            >
              <div className="text-[10px] font-mono uppercase tracking-[0.18em] text-[#DCEEFF]">
                {copy.title}
              </div>
              <div className="mt-2 text-[11px] leading-relaxed text-white/72">
                {copy.body}
              </div>
            </div>,
            document.body,
          )
        : null}
    </div>
  );
}

function getSubdivisionName(count: number): string {
  const names: Record<number, string> = {
    1: 'quarter notes',
    2: 'eighth notes',
    3: 'triplets',
    4: 'sixteenth notes',
    5: 'quintuplets',
    6: 'sextuplets',
    7: 'septuplets',
    8: '32nd notes',
    9: 'nonuplets',
  };

  return names[count] ?? `${count}-tuplets`;
}

function getStudyCountHelpText(layers: readonly Pick<PolyrhythmLayer, 'beatCount'>[], sharedStepCount: number): string {
  const counts = layers.map((layer) => Math.max(1, Math.round(layer.beatCount)));
  const uniqueCounts = Array.from(new Set(counts));
  const ratioLabel = counts.join(':');

  if (counts.length === 2) {
    const [first, second] = counts;
    if (first === second) {
      return `${ratioLabel} uses the same ${first}-step count on both layers, so it resolves after ${sharedStepCount} shared steps. No cross-rhythm translation is needed; both layers share the same grid.`;
    }
    return `${ratioLabel} meets again after ${sharedStepCount} shared steps. You can count it as ${getSubdivisionName(first)} in groups of ${second} over ${second}/4, or ${getSubdivisionName(second)} in groups of ${first} over ${first}/4. In plain terms: feel ${first}s across ${second} beats, or ${second}s across ${first} beats.`;
  }

  if (uniqueCounts.length === 1) {
    const [count] = uniqueCounts;
    return `${ratioLabel} uses the same ${count}-step count on every layer, so it resolves after ${sharedStepCount} shared steps. All layers share one grid.`;
  }

  const anchorOptions = uniqueCounts.slice(0, 4).map((count) => `${count}/4`).join(', ');
  const extra = uniqueCounts.length > 4 ? ', and the other unique layer counts' : '';
  const repeated = uniqueCounts.length < counts.length
    ? ' Repeated counts share the same feel, so read each unique count once.'
    : '';
  return `${ratioLabel} meets again after ${sharedStepCount} shared steps. For 3+ layers, choose one layer as the anchor beat. Count ${anchorOptions}${extra}, then hear the remaining layers as even subdivisions across that bar.${repeated} The anchor is the feel; the shared steps show where everything lines up again.`;
}

function RiffRollEditor({
  activeSteps,
  accents,
  color,
  selectedStepIndex,
  onPressStep,
  onLongPressStep,
  labelPrefix,
  compact = false,
  stretchToFill = false,
}: {
  activeSteps: boolean[];
  accents: boolean[];
  color: string;
  selectedStepIndex: number | null;
  onPressStep: (stepIndex: number) => void;
  onLongPressStep?: (stepIndex: number) => void;
  labelPrefix: string;
  compact?: boolean;
  stretchToFill?: boolean;
}) {
  const buttonRefs = useRef<Array<HTMLButtonElement | null>>([]);
  const longPressTimeoutRef = useRef<number | null>(null);
  const longPressStepRef = useRef<number | null>(null);
  const longPressFiredRef = useRef(false);
  const groupSize = getStepStripGroupSize(activeSteps.length);

  const clearLongPress = useCallback(() => {
    if (longPressTimeoutRef.current != null) {
      window.clearTimeout(longPressTimeoutRef.current);
      longPressTimeoutRef.current = null;
    }
  }, []);

  useEffect(() => {
    if (selectedStepIndex == null) {
      return;
    }
    buttonRefs.current[selectedStepIndex]?.scrollIntoView({
      block: 'nearest',
      inline: 'center',
      behavior: 'smooth',
    });
  }, [activeSteps.length, selectedStepIndex]);

  useEffect(() => clearLongPress, [clearLongPress]);

  return (
    <div className={stretchToFill ? 'w-full' : '-mx-1 overflow-x-auto pb-1 [scrollbar-width:none]'}>
      <div
        className={stretchToFill ? 'grid w-full gap-2' : 'flex gap-2 px-1'}
        style={
          stretchToFill
            ? { gridTemplateColumns: `repeat(${Math.max(1, activeSteps.length)}, minmax(0, 1fr))` }
            : undefined
        }
      >
        {activeSteps.map((active, index) => {
          const accented = Boolean(accents[index]);
          const selected = selectedStepIndex === index;
          const marker = index % groupSize === 0;
          return (
            <button
              key={`${labelPrefix}-${index}`}
              ref={(node) => {
                buttonRefs.current[index] = node;
              }}
              type="button"
              data-riff-step-control="true"
              onPointerDown={(event) => {
                if (!onLongPressStep) {
                  return;
                }
                event.currentTarget.setPointerCapture?.(event.pointerId);
                clearLongPress();
                longPressFiredRef.current = false;
                longPressStepRef.current = index;
                longPressTimeoutRef.current = window.setTimeout(() => {
                  longPressFiredRef.current = true;
                  onLongPressStep(index);
                }, 420);
              }}
              onPointerUp={clearLongPress}
              onPointerCancel={clearLongPress}
              onPointerLeave={clearLongPress}
              onClick={() => {
                if (longPressFiredRef.current && longPressStepRef.current === index) {
                  longPressFiredRef.current = false;
                  longPressStepRef.current = null;
                  return;
                }
                onPressStep(index);
              }}
              className={`relative border text-center transition-transform active:scale-[0.97] ${
                compact ? 'rounded-xl px-2 py-1.5' : 'rounded-2xl px-2.5 py-2'
              } ${
                stretchToFill ? 'min-w-0 w-full' : compact ? 'min-w-[42px]' : 'min-w-[50px]'
              }`}
              style={{
                background: selected
                  ? `${color}22`
                  : active
                    ? `${color}12`
                    : 'rgba(255,255,255,0.035)',
                borderColor: selected
                  ? `${color}82`
                  : active
                    ? `${color}34`
                    : marker
                      ? 'rgba(255,255,255,0.14)'
                      : 'rgba(255,255,255,0.08)',
                boxShadow: selected ? `0 0 0 1px ${color}2f inset` : 'none',
              }}
              aria-label={`Toggle ${labelPrefix} step ${index + 1}`}
            >
              <div
                className={`${compact ? 'text-[8px]' : 'text-[9px]'} font-mono uppercase tracking-[0.14em]`}
                style={{ color: selected ? color : 'rgba(255,255,255,0.48)' }}
              >
                {index + 1}
              </div>
              <div className={`${compact ? 'mt-1.5' : 'mt-2'} flex items-center justify-center gap-1`}>
                <span
                  className={`${compact ? 'h-2.5 w-2.5' : 'h-3 w-3'} rounded-full border`}
                  style={{
                    background: active ? color : 'rgba(255,255,255,0.08)',
                    borderColor: active ? `${color}cc` : 'rgba(255,255,255,0.12)',
                    boxShadow: active ? `0 0 0 1px ${color}25` : 'none',
                  }}
                />
                {accented ? (
                  <span
                    className="inline-flex h-4 min-w-[16px] items-center justify-center rounded-full border px-1 text-[8px] font-mono uppercase tracking-[0.08em]"
                    style={{
                      borderColor: `${color}44`,
                      background: `${color}16`,
                      color,
                    }}
                  >
                    A
                  </span>
                ) : null}
              </div>
              <div className={`${compact ? 'mt-1.5 text-[7px]' : 'mt-2 text-[8px]'} font-mono uppercase tracking-[0.14em] text-white/34`}>
                {active ? 'Hit' : 'Rest'}
              </div>
            </button>
          );
        })}
      </div>
    </div>
  );
}

function RiffCellSequenceEditor({
  study,
  selectedCellLabel,
  onSetEnabled,
  onSelectCell,
  onAddCell,
  onAppendCell,
  onRemoveLastCell,
  onDeleteCell,
  onResetSequence,
  onSetSequenceBars,
  onSetSequenceBarsMode,
  onSetSequenceEntryBars,
  onSetSequenceEntryRepeats,
  onSetSequenceEntryDurationMode,
  onSetCellColor,
  onRandomizeCells,
  colorEditingLocked = false,
  onLockedColorClick,
  sequenceLocked = false,
  onLockedSequenceClick,
  compact = false,
}: {
  study: RiffCycleStudy;
  selectedCellLabel: RiffSequenceCellLabel;
  onSetEnabled: (enabled: boolean) => void;
  onSelectCell: (label: RiffSequenceCellLabel) => void;
  onAddCell: () => void;
  onAppendCell: (label: RiffSequenceCellLabel) => void;
  onRemoveLastCell: () => void;
  onDeleteCell: (label: RiffSequenceCellLabel) => void;
  onResetSequence: () => void;
  onSetSequenceBars: (bars: number) => void;
  onSetSequenceBarsMode: (mode: 'global' | 'per-cell') => void;
  onSetSequenceEntryBars: (sequenceIndex: number, bars: number) => void;
  onSetSequenceEntryRepeats: (sequenceIndex: number, repeats: number) => void;
  onSetSequenceEntryDurationMode: (sequenceIndex: number, mode: RiffSequenceEntryDurationMode) => void;
  onSetCellColor: (label: RiffSequenceCellLabel, color: string) => void;
  onRandomizeCells: () => void;
  colorEditingLocked?: boolean;
  onLockedColorClick?: () => void;
  sequenceLocked?: boolean;
  onLockedSequenceClick?: () => void;
  compact?: boolean;
}) {
  const resetStepCount = getResetStepCount(study);
  const sequenceResetBars = Math.max(1, Math.min(RIFF_MAX_RESET_BARS, Math.round(study.riffSequenceBars || 4)));
  const cells = study.riffCells ?? [];
  const sequence = study.riffSequence ?? [];
  const sequenceBarsMode = study.riffSequenceBarsMode === 'per-cell' ? 'per-cell' : 'global';
  const sequenceEntryBars = sequence.map((_, index) =>
    Math.max(1, Math.min(RIFF_MAX_RESET_BARS, Math.round(study.riffSequenceEntryBars?.[index] ?? sequenceResetBars))),
  );
  const sequenceEntryRepeats = sequence.map((_, index) =>
    Math.max(1, Math.min(RIFF_MAX_SEQUENCE_REPEATS, Math.round(study.riffSequenceEntryRepeats?.[index] ?? 1))),
  );
  const sequenceEntryDurationModes = sequence.map((_, index): RiffSequenceEntryDurationMode =>
    study.riffSequenceEntryDurationModes?.[index] === 'bars' ? 'bars' : 'patterns',
  );
  const sequenceTotalBars =
    sequenceBarsMode === 'per-cell'
      ? sequence.reduce((sum, label, index) => {
          const cell = cells.find((candidate) => candidate.label === label);
          const mode = sequenceEntryDurationModes[index] ?? 'patterns';
          if (mode === 'bars') {
            return sum + (sequenceEntryBars[index] ?? sequenceResetBars);
          }
          const stepCount = Math.max(1, Math.round(cell?.stepCount ?? study.riff.stepCount));
          const repeats = sequenceEntryRepeats[index] ?? 1;
          return sum + (stepCount * repeats) / Math.max(1, getReferenceStepsPerBar(study.reference));
        }, 0)
      : sequenceResetBars;
  const sequenceTotalBarsLabel = sequenceTotalBars.toLocaleString(undefined, {
    maximumFractionDigits: 2,
  });
  const sequenceLabel = sequence.length > 0 ? sequence.join(' ') : 'A';
  const selectedCell =
    cells.find((cell) => cell.label === selectedCellLabel) ?? cells[0] ?? null;
  const selectedCellColor = selectedCell?.color ?? study.riff.color;
  const sequenceStepTotal = Math.max(
    1,
    sequence.reduce((sum, label, index) => {
      const cell = cells.find((candidate) => candidate.label === label);
      const repeatCount = sequenceEntryRepeats[index] ?? 1;
      return sum + Math.max(1, Math.round(cell?.stepCount ?? study.riff.stepCount)) * repeatCount;
    }, 0),
  );
  const sequenceNaturalResolveBars =
    sequenceStepTotal / gcd(sequenceStepTotal, Math.max(1, getReferenceStepsPerBar(study.reference)));
  const canAddCell = cells.length < RIFF_SEQUENCE_CELL_LABELS.length;
  const getCellVisualColor = (label: RiffSequenceCellLabel): string =>
    cells.find((cell) => cell.label === label)?.color ?? study.riff.color;

  return (
    <div
      className={`rounded-xl border ${compact ? 'px-2 py-1.5' : 'px-3 py-2.5'} ${study.riffSequenceEnabled ? 'space-y-1.5' : 'space-y-0'}`}
      style={{
        background: study.riffSequenceEnabled
          ? `linear-gradient(180deg, ${selectedCellColor}10, rgba(255,255,255,0.025))`
          : 'rgba(255,255,255,0.03)',
        borderColor: study.riffSequenceEnabled ? `${selectedCellColor}30` : 'rgba(255,255,255,0.09)',
      }}
    >
      <div className="flex items-center justify-between gap-3">
        <div className="min-w-0">
          <InlineInfoLabel
            infoId="riff_cell_sequencer"
            label="Cell Sequencer"
            labelClassName="text-[10px] font-mono uppercase tracking-[0.18em]"
            labelStyle={{ color: study.riffSequenceEnabled ? selectedCellColor : 'rgba(255,255,255,0.52)' }}
          />
          <span
            className="ml-1.5 inline-flex rounded-full border px-1.5 py-0.5 align-middle text-[6.5px] font-mono uppercase tracking-[0.14em]"
            style={{
              borderColor: study.riffSequenceEnabled ? `${selectedCellColor}42` : 'rgba(255,255,255,0.12)',
              color: study.riffSequenceEnabled ? selectedCellColor : 'rgba(255,255,255,0.38)',
              background: study.riffSequenceEnabled ? `${selectedCellColor}10` : 'rgba(255,255,255,0.035)',
            }}
          >
            Beta
          </span>
          {study.riffSequenceEnabled ? (
            <div className="mt-0.5 text-[9px] leading-snug text-white/40">
              Build pattern cells, arrange them, then set the section length.
            </div>
          ) : null}
        </div>
        <StudyShellButton
          size="compact"
          tone="amber"
          highlighted={study.riffSequenceEnabled && !sequenceLocked}
          locked={sequenceLocked}
          onLockedClick={onLockedSequenceClick}
          className={compact ? '!h-7 rounded-lg px-2 text-[8.5px]' : undefined}
          onClick={() => onSetEnabled(!study.riffSequenceEnabled)}
        >
          {sequenceLocked ? 'Pro' : study.riffSequenceEnabled ? 'On' : 'Off'}
        </StudyShellButton>
      </div>

      {study.riffSequenceEnabled && !sequenceLocked ? (
        <>
          <div className="space-y-1">
            <div className="flex items-center justify-between gap-3">
              <InlineInfoLabel
                infoId="riff_cell_library"
                label="Cell Library"
                labelClassName="text-[9px] font-mono uppercase tracking-[0.15em] text-white/42"
              />
              {selectedCell ? (
                <div className="flex items-center gap-1.5">
                  <button
                    type="button"
                    onClick={onRandomizeCells}
                    className="rounded-lg border px-2 py-1 text-[7px] font-mono uppercase tracking-[0.12em] transition-transform active:scale-[0.97]"
                    style={{
                      background: 'rgba(127,215,255,0.07)',
                      borderColor: 'rgba(127,215,255,0.2)',
                      color: '#BFEAFF',
                    }}
                    aria-label="Randomize cell sequencer cells"
                  >
                    Random
                  </button>
                  {cells.length > 1 ? (
                    <button
                      type="button"
                      onClick={() => onDeleteCell(selectedCell.label)}
                      className="inline-flex h-7 w-7 items-center justify-center rounded-lg border transition-transform active:scale-[0.97]"
                      style={{
                        background: 'rgba(255,45,85,0.08)',
                        borderColor: 'rgba(255,45,85,0.22)',
                        color: '#FF4778',
                      }}
                      aria-label={`Delete Cell ${selectedCell.label}`}
                    >
                      <Trash2 size={12} />
                    </button>
                  ) : null}
                  <LimitedColorPickerButton
                    colors={RIFF_CYCLE_COLORS}
                    value={selectedCell.color}
                    onChange={(color) => onSetCellColor(selectedCell.label, color)}
                    label={`Pick Cell ${selectedCell.label} color`}
                    locked={colorEditingLocked}
                    onLockedClick={onLockedColorClick}
                  />
                </div>
              ) : null}
            </div>
            <div className="-mx-0.5 overflow-x-auto pb-0.5 [scrollbar-width:none]">
              <div className="flex min-w-max gap-1 px-0.5">
                {cells.map((cell) => {
                  const selected = cell.label === selectedCell?.label;
                  const cellColor = getCellVisualColor(cell.label);
                  const previewLimit = Math.min(12, cell.stepCount);
                  const previewSteps = cell.activeSteps.slice(0, previewLimit);
                  const hitCount = cell.activeSteps.filter(Boolean).length;
                  const accentCount = cell.activeSteps.filter((active, stepIndex) => active && cell.accents[stepIndex]).length;
                  return (
                    <button
                      key={cell.label}
                      type="button"
                      onClick={() => onSelectCell(cell.label)}
                      className={`${compact ? 'min-h-10 min-w-[3.35rem] px-1.5' : 'min-h-11 min-w-14 px-2'} rounded-lg border text-[9px] font-mono uppercase tracking-[0.12em] transition-transform active:scale-[0.97]`}
                      style={{
                        background: selected ? `${cellColor}18` : 'rgba(255,255,255,0.04)',
                        borderColor: selected ? `${cellColor}66` : 'rgba(255,255,255,0.1)',
                        color: selected ? cellColor : 'rgba(255,255,255,0.58)',
                        boxShadow: selected ? `0 0 0 1px ${cellColor}18 inset` : 'none',
                      }}
                    >
                      <span className="flex items-center justify-between gap-3 leading-none">
                        <span>{cell.label}</span>
                        <span className="text-[7px] tracking-[0.08em] opacity-60">{cell.stepCount}</span>
                      </span>
                      <span className="mt-1 flex justify-center gap-0.5" aria-hidden="true">
                        {previewSteps.map((active, stepIndex) => {
                          const accented = cell.accents[stepIndex];
                          return (
                            <span
                              key={`cell-preview-${cell.label}-${stepIndex}`}
                              className="h-1.5 w-1.5 rounded-full"
                              style={{
                                background: active ? cellColor : 'rgba(255,255,255,0.16)',
                                boxShadow: accented ? `0 0 0 1px ${cellColor}` : 'none',
                                opacity: active ? 1 : 0.7,
                              }}
                            />
                          );
                        })}
                      </span>
                      <span className="mt-1 block text-[6.5px] tracking-[0.08em] opacity-58">
                        {hitCount} hit{hitCount === 1 ? '' : 's'}{accentCount > 0 ? ` / ${accentCount} acc` : ''}
                      </span>
                    </button>
                  );
                })}
                <button
                  type="button"
                  onClick={onAddCell}
                  disabled={!canAddCell}
                  className={`${compact ? 'h-8 w-8' : 'h-9 w-9'} inline-flex items-center justify-center rounded-lg border transition-transform active:scale-[0.97] disabled:opacity-40`}
                  style={{
                    background: 'rgba(255,255,255,0.045)',
                    borderColor: 'rgba(255,255,255,0.12)',
                    color: 'rgba(255,255,255,0.7)',
                  }}
                  aria-label="Add riff cell"
                >
                  <Plus size={14} />
                </button>
              </div>
            </div>
          </div>

          <div className="space-y-1.5 rounded-lg border border-white/10 bg-black/[0.12] px-2 py-2">
            <div className="flex items-center justify-between gap-3">
              <InlineInfoLabel
                infoId="riff_sequence_order"
                label="Sequence Order"
                labelClassName="text-[9px] font-mono uppercase tracking-[0.15em] text-white/42"
              />
              <div className="text-[8px] font-mono uppercase tracking-[0.12em] text-white/38">
                {sequenceTotalBarsLabel} bar{sequenceTotalBars === 1 ? '' : 's'} total
              </div>
            </div>

            <div className="flex min-h-8 flex-wrap items-stretch gap-1">
              {sequence.map((label, index) => {
                const exists = cells.some((cell) => cell.label === label);
                const cellColor = getCellVisualColor(label);
                const entryBars = sequenceEntryBars[index] ?? sequenceResetBars;
                const entryRepeats = sequenceEntryRepeats[index] ?? 1;
                const entryDurationMode = sequenceEntryDurationModes[index] ?? 'patterns';
                const entryValue = entryDurationMode === 'bars' ? entryBars : entryRepeats;
                const entrySpan =
                  sequenceBarsMode === 'per-cell'
                    ? entryDurationMode === 'bars'
                      ? `${entryBars}b`
                      : `${entryRepeats}x`
                    : null;
              return (
                <div key={`sequence-cell-${index}-${label}`} className="inline-flex items-center gap-1">
                  <div className="inline-flex flex-col items-center gap-0.5">
                    <button
                      type="button"
                      onClick={() => {
                        if (exists) {
                          onSelectCell(label);
                        }
                      }}
                      className="inline-flex min-h-8 min-w-10 flex-col items-center justify-center rounded-md border px-1.5 font-mono uppercase transition-transform active:scale-[0.97]"
                      style={{
                        background:
                          exists && label === selectedCell?.label
                            ? `${cellColor}18`
                            : 'rgba(255,255,255,0.04)',
                        borderColor:
                          exists && label === selectedCell?.label
                            ? `${cellColor}52`
                            : 'rgba(255,255,255,0.09)',
                        color: exists ? (label === selectedCell?.label ? cellColor : 'rgba(255,255,255,0.62)') : 'rgba(255,255,255,0.24)',
                      }}
                    >
                      <span className="text-[7px] leading-none tracking-[0.08em] opacity-55">{index + 1}</span>
                      <span className="mt-0.5 text-[10px] leading-none tracking-[0.12em]">{label}</span>
                      {entrySpan != null ? (
                        <span className="mt-0.5 text-[6.5px] leading-none tracking-[0.08em] opacity-56">
                          {entrySpan}
                        </span>
                      ) : null}
                    </button>
                    {sequenceBarsMode === 'per-cell' ? (
                      <div className="flex overflow-hidden rounded-md border border-white/8 bg-white/[0.035]">
                        <label className="flex items-center gap-0.5 px-1 py-0.5">
                          <input
                            type="number"
                            inputMode="numeric"
                            min={1}
                            max={entryDurationMode === 'bars' ? RIFF_MAX_RESET_BARS : RIFF_MAX_SEQUENCE_REPEATS}
                            value={entryValue}
                            onFocus={(event) => event.currentTarget.select()}
                            onChange={(event) => {
                              const nextValue = Number.parseInt(event.currentTarget.value, 10) || entryValue;
                              if (entryDurationMode === 'bars') {
                                onSetSequenceEntryBars(index, nextValue);
                              } else {
                                onSetSequenceEntryRepeats(index, nextValue);
                              }
                            }}
                            className="h-5 w-6 bg-transparent text-center text-[9px] font-mono text-white/76 outline-none"
                            aria-label={
                              entryDurationMode === 'bars'
                                ? `Set bars for sequence ${index + 1} cell ${label}`
                                : `Set cell plays for sequence ${index + 1} cell ${label}`
                            }
                          />
                        </label>
                        <button
                          type="button"
                          onClick={() =>
                            onSetSequenceEntryDurationMode(index, entryDurationMode === 'bars' ? 'patterns' : 'bars')
                          }
                          className="border-l border-white/8 px-1.5 text-[6.5px] font-mono uppercase tracking-[0.08em] transition"
                          style={{
                            color: entryDurationMode === 'bars' ? 'rgba(255,255,255,0.42)' : cellColor,
                            background: entryDurationMode === 'patterns' ? `${cellColor}10` : 'rgba(255,255,255,0.025)',
                          }}
                          aria-label={`Use ${entryDurationMode === 'bars' ? 'cell pattern plays' : 'bars'} for sequence ${index + 1}`}
                        >
                          {entryDurationMode === 'bars' ? 'Bar' : 'Cell'}
                        </button>
                      </div>
                    ) : null}
                  </div>
                  {index < sequence.length - 1 ? (
                    <span className="text-[10px] text-white/24 self-center">-&gt;</span>
                  ) : null}
                </div>
              );
            })}
            </div>

            <div className="space-y-1">
              <div className="text-[8px] font-mono uppercase tracking-[0.14em] text-white/34">
                Add To Sequence
              </div>
              <div className="grid gap-1.5" style={{ gridTemplateColumns: `repeat(${Math.max(1, Math.min(4, cells.length))}, minmax(0, 1fr))` }}>
                {cells.map((cell) => (
                  <button
                    key={`append-${cell.label}`}
                    type="button"
                    onClick={() => onAppendCell(cell.label)}
                    className="rounded-lg border px-2 py-1.5 text-[9px] font-mono uppercase tracking-[0.12em] transition-transform active:scale-[0.97]"
                    style={{
                      background: `${cell.color}0f`,
                      borderColor: `${cell.color}24`,
                      color: cell.color,
                    }}
                  >
                    +{cell.label}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-2 gap-1">
              <StudyShellButton
                size="compact"
                tone="neutral"
                className="!h-[1.55rem] rounded-lg text-[8.5px]"
                onClick={onRemoveLastCell}
                disabled={sequence.length <= 1}
              >
                Undo
              </StudyShellButton>
              <StudyShellButton
                size="compact"
                tone="neutral"
                className="!h-[1.55rem] rounded-lg text-[8.5px]"
                icon={<RotateCcw size={13} />}
                onClick={onResetSequence}
              >
                Clear Order
              </StudyShellButton>
            </div>

            <div className="space-y-1">
              <div className="flex items-center justify-between gap-2">
                <InlineInfoLabel
                  infoId="riff_section_bars"
                  label="Section Bars"
                  labelClassName="text-[9px] font-mono uppercase tracking-[0.15em] text-white/42"
                />
                <div className="grid grid-cols-2 overflow-hidden rounded-md border border-white/10 bg-white/[0.035]">
                  {(['global', 'per-cell'] as const).map((mode) => (
                    <button
                      key={mode}
                      type="button"
                      onClick={() => onSetSequenceBarsMode(mode)}
                      className="px-1.5 py-0.5 text-[6.5px] font-mono uppercase tracking-[0.1em] transition"
                      style={{
                        background: sequenceBarsMode === mode ? 'rgba(255,209,102,0.16)' : 'transparent',
                        color: sequenceBarsMode === mode ? '#FFD166' : 'rgba(255,255,255,0.38)',
                      }}
                    >
                      {mode === 'global' ? 'Global' : 'Per Cell'}
                    </button>
                  ))}
                </div>
              </div>

              {sequenceBarsMode === 'global' ? (
                <div className="flex overflow-hidden rounded-lg border border-white/10 bg-white/[0.045]">
                  <input
                    type="number"
                    inputMode="numeric"
                    min={1}
                    max={RIFF_MAX_RESET_BARS}
                    value={sequenceResetBars}
                    onFocus={(event) => event.currentTarget.select()}
                    onChange={(event) => onSetSequenceBars(Number.parseInt(event.target.value, 10) || sequenceResetBars)}
                    className="min-w-0 flex-1 bg-transparent px-2.5 py-1.5 text-center text-[12px] font-light text-white outline-none"
                  />
                  <span className="flex items-center border-l border-white/10 px-2.5 text-[8px] font-mono uppercase tracking-[0.12em] text-white/42">
                    Bars
                  </span>
                </div>
              ) : (
                <div className="rounded-lg border border-white/10 bg-white/[0.035] px-2 py-1.5 text-center text-[7px] font-mono uppercase tracking-[0.1em] text-white/36">
                  Set each slot to Cell plays or Bar length
                </div>
              )}
            </div>

            {resetStepCount != null ? (
              <div
                className="rounded-lg border px-2 py-1.5 text-center text-[7px] font-mono uppercase tracking-[0.1em]"
                style={{
                  borderColor: 'rgba(127,215,255,0.18)',
                  background: 'rgba(127,215,255,0.07)',
                  color: '#BFEAFF',
                }}
              >
                {sequenceLabel} naturally resolves after {sequenceNaturalResolveBars.toLocaleString()} bar{sequenceNaturalResolveBars === 1 ? '' : 's'}
              </div>
            ) : null}
          </div>
        </>
      ) : null}
    </div>
  );
}

function RiffEndingReturnWindowPanel({
  landingWindowBars,
  landingEditableSlots,
  stepsPerBar,
  landingWindowSteps,
  landingOverrides,
  freeRestartMode = false,
  playing,
  playbackStateRef,
  className = '',
}: {
  landingWindowBars: number;
  landingEditableSlots: number;
  stepsPerBar: number;
  landingWindowSteps: number;
  landingOverrides: RiffCycleStudy['landingOverrides'];
  freeRestartMode?: boolean;
  playing: boolean;
  playbackStateRef: React.MutableRefObject<RiffCyclePlaybackState>;
  className?: string;
}) {
  const [activeBarIndex, setActiveBarIndex] = useState<number | null>(null);
  const [activeStepIndex, setActiveStepIndex] = useState<number | null>(null);

  useEffect(() => {
    if (!playing) {
      setActiveBarIndex(null);
      setActiveStepIndex(null);
      return;
    }

    let frame = 0;
    const update = () => {
      const currentAbsoluteReferenceStep = Math.floor(playbackStateRef.current.referenceProgress);
      const normalizedReferenceStep =
        ((currentAbsoluteReferenceStep % landingWindowSteps) + landingWindowSteps) % landingWindowSteps;
      const nextBarIndex = Math.min(
        landingWindowBars - 1,
        Math.floor(normalizedReferenceStep / stepsPerBar),
      );
      setActiveBarIndex((current) => (current === nextBarIndex ? current : nextBarIndex));
      const nextStepIndex =
        ((normalizedReferenceStep % stepsPerBar) + stepsPerBar) % stepsPerBar;
      setActiveStepIndex((current) => (current === nextStepIndex ? current : nextStepIndex));
      frame = window.requestAnimationFrame(update);
    };

    frame = window.requestAnimationFrame(update);
    return () => window.cancelAnimationFrame(frame);
  }, [landingWindowBars, landingWindowSteps, playbackStateRef, playing, stepsPerBar]);

  const visibleBarIndexes =
    landingWindowBars <= 8
      ? Array.from({ length: landingWindowBars }, (_, index) => index)
      : [0, 1, -1, landingWindowBars - 2, landingWindowBars - 1];
  const endingStartStep = Math.max(0, stepsPerBar - landingEditableSlots);

  return (
    <StudyShellPremiumPanel accent="#7FD7FF" className={`space-y-3 ${className}`}>
      <StudyShellPanel className="space-y-3">
        <div className="flex items-center justify-between gap-3">
          <div className="text-[9px] font-mono uppercase tracking-[0.18em] text-[#7FD7FF]/80">
            Return Window
          </div>
          <div className="rounded-full border border-[#7FD7FF]/20 bg-[#7FD7FF]/10 px-2.5 py-1 text-[8px] font-mono uppercase tracking-[0.14em] text-[#7FD7FF]">
            {landingWindowBars} {landingWindowBars === 1 ? 'Bar' : 'Bars'} Restart
          </div>
        </div>

        <div className="rounded-xl border border-[#7FD7FF]/16 bg-[#7FD7FF]/8 px-3 py-2 text-[11px] leading-relaxed text-white/58">
          The ending only happens at the end of the return cycle. These final slots play right before the riff comes back to beat 1.
          {freeRestartMode
            ? ' In Free restart, the blue ending dots follow the moving return point, so they show where the ending is now instead of one fixed bar.'
            : ''}
        </div>

        <div className="space-y-2">
          <div className="flex items-center gap-1.5">
            {visibleBarIndexes.map((barIndex, index) => {
              if (barIndex === -1) {
                return (
                  <div
                    key="ending-window-ellipsis"
                    className="flex h-9 w-7 items-center justify-center text-[12px] font-mono tracking-[0.16em] text-white/24"
                  >
                    ...
                  </div>
                );
              }
              const isEndingBar = barIndex === landingWindowBars - 1;
              const isActiveBar = activeBarIndex === barIndex;
              return (
                <div
                  key={`ending-window-bar-${barIndex}-${index}`}
                  className="flex h-9 min-w-0 flex-1 items-center justify-center rounded-xl border px-2 text-[9px] font-mono uppercase tracking-[0.14em] transition-all"
                  style={{
                    borderColor: isActiveBar
                      ? 'rgba(127,215,255,0.52)'
                      : isEndingBar
                        ? 'rgba(127,215,255,0.36)'
                        : 'rgba(255,255,255,0.08)',
                    background: isActiveBar
                      ? 'rgba(127,215,255,0.18)'
                      : isEndingBar
                        ? 'rgba(127,215,255,0.11)'
                        : 'rgba(255,255,255,0.035)',
                    color: isEndingBar ? '#7FD7FF' : 'rgba(255,255,255,0.58)',
                    boxShadow: isActiveBar
                      ? '0 0 20px rgba(127,215,255,0.12)'
                      : isEndingBar
                        ? 'inset 0 0 0 1px rgba(127,215,255,0.08)'
                        : 'none',
                  }}
                >
                  {isEndingBar ? 'End' : `Bar ${barIndex + 1}`}
                </div>
              );
            })}
          </div>

          <div className="flex items-stretch gap-1.5">
            {visibleBarIndexes.map((barIndex, index) => {
              if (barIndex === -1) {
                return (
                  <div
                    key="ending-window-step-ellipsis"
                    className="flex h-9 w-7 items-center justify-center text-[12px] font-mono tracking-[0.16em] text-white/18"
                  >
                    ...
                  </div>
                );
              }
              const isEndingBar = barIndex === landingWindowBars - 1;
              const isActiveBar = activeBarIndex === barIndex;
              const beatDivision = stepsPerBar % 4 === 0 ? Math.max(1, stepsPerBar / 4) : 1;
              return (
                <div
                  key={`ending-window-step-bar-${barIndex}-${index}`}
                  className="min-w-0 flex-1 rounded-xl border p-1"
                  style={{
                    borderColor: isActiveBar
                      ? 'rgba(127,215,255,0.34)'
                      : isEndingBar
                        ? 'rgba(127,215,255,0.24)'
                        : 'rgba(255,255,255,0.06)',
                    background: isActiveBar
                      ? 'rgba(127,215,255,0.08)'
                      : isEndingBar
                        ? 'rgba(127,215,255,0.055)'
                        : 'rgba(255,255,255,0.018)',
                  }}
                >
                  <div
                    className="grid h-7 gap-[2px]"
                    style={{ gridTemplateColumns: `repeat(${stepsPerBar}, minmax(0, 1fr))` }}
                  >
                    {Array.from({ length: stepsPerBar }, (_, stepIndex) => {
                      const isEndingSlot = isEndingBar && stepIndex >= endingStartStep;
                      const slotIndex = stepIndex - endingStartStep;
                      const overrideState = isEndingSlot ? landingOverrides[slotIndex] : null;
                      const isFilled = overrideState === 'on' || overrideState === 'accent';
                      const isAccent = overrideState === 'accent';
                      const isBeatStart = stepIndex % beatDivision === 0;
                      const isTrackerSlot = isActiveBar && activeStepIndex === stepIndex;
                      return (
                        <div
                          key={`ending-window-step-${barIndex}-${stepIndex}`}
                          className="relative min-w-0 rounded-[3px] border"
                          title={
                            isEndingSlot
                              ? `Ending slot ${slotIndex + 1}${isAccent ? ' accent' : isFilled ? ' hit' : ''}`
                              : `Bar ${barIndex + 1}, slot ${stepIndex + 1}`
                          }
                          style={{
                            borderColor: isEndingSlot
                              ? 'rgba(127,215,255,0.48)'
                              : isBeatStart
                                ? 'rgba(255,255,255,0.13)'
                                : 'rgba(255,255,255,0.055)',
                            background: isEndingSlot
                              ? isFilled
                                ? 'rgba(127,215,255,0.72)'
                                : 'rgba(127,215,255,0.22)'
                              : isBeatStart
                                ? 'rgba(255,255,255,0.08)'
                                : 'rgba(255,255,255,0.035)',
                            boxShadow: isTrackerSlot
                              ? '0 0 0 1px rgba(255,255,255,0.9), 0 0 14px rgba(255,255,255,0.34)'
                              : isEndingSlot
                                ? isFilled
                                  ? '0 0 12px rgba(127,215,255,0.36)'
                                  : '0 0 8px rgba(127,215,255,0.16)'
                                : 'none',
                          }}
                        >
                          {isTrackerSlot ? (
                            <span
                              className="absolute left-1/2 top-1/2 h-2 w-2 -translate-x-1/2 -translate-y-1/2 rounded-full bg-white"
                              style={{
                                boxShadow: '0 0 10px rgba(255,255,255,0.75)',
                              }}
                            />
                          ) : null}
                        </div>
                      );
                    })}
                  </div>
                </div>
              );
            })}
          </div>

          <div className="flex items-center justify-between gap-2 text-[8px] font-mono uppercase tracking-[0.14em] text-white/34">
            <span>Each bar shows subdivision slots</span>
            <span className="text-[#7FD7FF]/70">Final slots to Beat 1</span>
          </div>
        </div>
      </StudyShellPanel>
    </StudyShellPremiumPanel>
  );
}

