  const handleAddPolyrhythmLayer = useCallback(() => {
    let nextLayerId: string | null = null;
    let hitLayerLimit = false;
    if (!requireEditablePolyrhythmStudy()) {
      return;
    }
    if (
      !canUseProFeature(effectivePlan, 'study-layers') &&
      polyrhythmStudy.layers.length >= FREE_STUDY_LAYER_LIMIT
    ) {
      showProPrompt('study-layers');
      return;
    }
    setPolyrhythmStudy((current) => {
      if (current.layers.length >= MAX_POLYRHYTHM_LAYERS) {
        hitLayerLimit = true;
        return current;
      }
      const lastLayer = current.layers[current.layers.length - 1];
      const nextLayerIndex = current.layers.length;
      const editableStepLimit = canUseProFeature(effectivePlan, 'study-extended-steps')
        ? 64
        : FREE_STUDY_STEP_LIMIT;
      const usedBeatCounts = new Set(current.layers.map((layer) => layer.beatCount));
      const preferredBeatCount =
        STANDARD_STUDY_LAYER_COUNTS.find((count) => !usedBeatCounts.has(count)) ??
        STANDARD_STUDY_LAYER_COUNTS[nextLayerIndex % STANDARD_STUDY_LAYER_COUNTS.length] ??
        ((lastLayer?.beatCount ?? 5) + 1);
      const nextBeatCount = Math.min(editableStepLimit, preferredBeatCount);
      const nextRadius = Math.max(78, (lastLayer?.radius ?? 230) - 34);
      const nextColor =
        POLYRHYTHM_LAYER_COLORS[nextLayerIndex % POLYRHYTHM_LAYER_COLORS.length];
      const nextLayer = createPolyrhythmLayer(nextBeatCount, {
        radius: nextRadius,
        rotationOffset: 0,
        color: nextColor,
        activeSteps: createEvenPulseMask(nextBeatCount, nextBeatCount),
        pitchHz: Math.min(960, 180 + nextLayerIndex * 66),
        gain: Math.max(0.04, 0.12 - nextLayerIndex * 0.01),
      });
      nextLayerId = nextLayer.id;

      return {
        ...current,
        layers: [
          ...current.layers,
          nextLayer,
        ],
      };
    });
    if (hitLayerLimit) {
      toast.message(`Study is limited to ${MAX_POLYRHYTHM_LAYERS} layers.`);
      return;
    }
    if (nextLayerId) {
      setSelectedPolyrhythmLayerId(nextLayerId);
      setSelectedPolyrhythmStep(null);
    }
  }, [effectivePlan, polyrhythmStudy.layers.length, requireEditablePolyrhythmStudy]);

  const handleRemovePolyrhythmLayer = useCallback((layerId: string) => {
    if (!requireEditablePolyrhythmStudy()) {
      return;
    }
    setPolyrhythmStudy((current) => {
      if (current.layers.length <= 1) {
        return current;
      }

      return {
        ...current,
        layers: current.layers.filter((layer) => layer.id !== layerId),
      };
    });
    setSelectedPolyrhythmStep((current) => (current?.layerId === layerId ? null : current));
  }, [requireEditablePolyrhythmStudy]);

  const handleUpdatePolyrhythmLayer = useCallback(
    (layerId: string, updates: Partial<PolyrhythmLayer>) => {
      if (!requireEditablePolyrhythmStudy()) {
        return;
      }
      if (
        typeof updates.color === 'string' &&
        !canUseProFeature(effectivePlan, 'color-editing')
      ) {
        showProPrompt('color-editing');
        return;
      }
      if (
        (typeof updates.pitchHz === 'number' ||
          typeof updates.gain === 'number' ||
          typeof updates.soundEnabled === 'boolean') &&
        !canUseProFeature(effectivePlan, 'sound-editing')
      ) {
        showProPrompt('sound-editing');
        return;
      }
      setPolyrhythmStudy((current) => ({
        ...current,
        layers: current.layers.map((layer) => {
          if (layer.id !== layerId) {
            return layer;
          }

          return {
            ...layer,
            ...updates,
            radius:
              updates.radius == null
                ? layer.radius
                : Math.max(60, Math.min(320, Math.round(updates.radius))),
            rotationOffset:
              updates.rotationOffset == null
                ? layer.rotationOffset
                : ((updates.rotationOffset % 360) + 360) % 360,
            pitchHz:
              updates.pitchHz == null
                ? layer.pitchHz
                : Math.max(90, Math.min(1400, Math.round(updates.pitchHz))),
            gain:
              updates.gain == null
                ? layer.gain
                : Math.max(0.02, Math.min(0.28, Number(updates.gain))),
          };
        }),
      }));
    },
    [effectivePlan, requireEditablePolyrhythmStudy],
  );

  const handleSetPolyrhythmLayerColor = useCallback(
    (layerId: string, color: string) => {
      setSelectedPolyrhythmLayerId(layerId);
      setSelectedPolyrhythmStep(null);
      handleUpdatePolyrhythmLayer(layerId, { color });
    },
    [handleUpdatePolyrhythmLayer],
  );

  const handleSetPolyrhythmLayerBeatCount = useCallback(
    (layerId: string, beatCount: number) => {
      if (!requireEditablePolyrhythmStudy()) {
        return;
      }
      const nextBeatCount = Math.max(2, Math.min(64, Math.round(beatCount || 0)));
      if (
        !canUseProFeature(effectivePlan, 'study-extended-steps') &&
        nextBeatCount > FREE_STUDY_STEP_LIMIT
      ) {
        showProPrompt('study-extended-steps');
        return;
      }
      setPolyrhythmStudy((current) => ({
        ...current,
        layers: current.layers.map((layer) =>
          layer.id === layerId ? updateLayerBeatCount(layer, nextBeatCount) : layer,
        ),
      }));
      setSelectedPolyrhythmStep((current) => {
        if (!current || current.layerId !== layerId) {
          return current;
        }
        return null;
      });
    },
    [effectivePlan, requireEditablePolyrhythmStudy],
  );

